// Get existing sheet headers from Sheets API GET response
const headerResponse = $input.item.json;
const existingHeaders = (headerResponse.values && headerResponse.values[0])
  ? headerResponse.values[0].filter(h => h != null && h.toString().trim() !== '')
  : [];

// Get the flattened receipt data from Format Receipt Data
const receiptData = $('Format Receipt Data1').item.json;
const receiptKeys = Object.keys(receiptData);

// Find any fields that don't yet have a column in the sheet
const newKeys = receiptKeys.filter(k => !existingHeaders.includes(k));
const allHeaders = [...existingHeaders, ...newKeys];

if (newKeys.length > 0) {
  console.log('Adding new columns: ' + newKeys.join(', '));
}

// Pass receipt data through + _headers so Write Headers node can update row 1.
// _headers won't write to the sheet since no column by that name exists there.
return [{
  json: {
    ...receiptData,
    _headers: JSON.stringify(allHeaders)
  }
}];

// Write Headers outputs the Sheets API response, not the receipt data.
// Pull the receipt data back from Sync Columns and strip the internal _headers field.
const syncData = $('Sync Columns').item.json;
const { _headers, ...receiptData } = syncData;
return [{ json: receiptData }];

// Parse AI response JSON
let raw = $json.output ?? '';
if (typeof raw !== 'string') raw = JSON.stringify(raw);
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (!jsonMatch) throw new Error('No JSON found in AI response: ' + raw.substring(0, 200));
const data = JSON.parse(jsonMatch[0]);

// Format a single line item as a readable summary string
function formatLineItem(item) {
  const name = item.name || item.description || item.item || item.service || item.product || 'Item';
  const qtyKey = Object.keys(item).find(k => /qty|quantity|count|gallons|gal|units|hrs|hours/.test(k.toLowerCase()));
  const priceKey = Object.keys(item).find(k => /unit_?price|price_?per|rate|each|per_?gal|cost/.test(k.toLowerCase()));
  const totalKey = Object.keys(item).find(k => /^total$|line_?total|item_?total|amount|extended/.test(k.toLowerCase()));
  const parts = [name];
  if (qtyKey && item[qtyKey] != null) parts.push(`x${item[qtyKey]}`);
  if (priceKey && item[priceKey] != null) parts.push(`@ $${item[priceKey]}`);
  if (totalKey && item[totalKey] != null) parts.push(`= $${item[totalKey]}`);
  return parts.join(' ');
}

// Flatten — arrays of objects become a readable pipe-delimited summary string
function flatten(obj, prefix = '') {
  const result = {};
  for (const [key, val] of Object.entries(obj)) {
    if (val === null || val === undefined || val === '') continue;
    const fullKey = prefix ? `${prefix}_${key}` : key;
    if (Array.isArray(val)) {
      if (val.length === 0) continue;
      if (typeof val[0] === 'object' && val[0] !== null) {
        result[fullKey] = val.map(formatLineItem).join(' | ');
      } else {
        result[fullKey] = val.join(' | ');
      }
    } else if (typeof val === 'object') {
      Object.assign(result, flatten(val, fullKey));
    } else {
      result[fullKey] = val;
    }
  }
  return result;
}

// Always output exactly one row per receipt
return [{ json: flatten(data) }];
